dict_structure

 dict_structure (the_dict:dict, indent='    ')



Code
print(dict_structure({
    "key_1": "A string",
    "longerkey_2": [1,2,3],
    "key_3": dict(a=[], b="2", c=3)
}))


    key_1           :   &lt;class 'str'&gt;
    longerkey_2     :   &lt;class 'list'&gt;
    key_3           :   &lt;class 'dict'&gt;
        a               :   &lt;class 'list'&gt;
        b               :   &lt;class 'str'&gt;
        c               :   &lt;class 'int'&gt;
